import { Sudoku } from './sudoku';
// 如果是在测试环境，这些 store 可能会报错，我们加个保护或者只在有浏览器时调用
import { cursor } from './stores/cursor';
import { difficulty } from './stores/difficulty';
import { gamePaused } from './stores/game';
import { timer } from './stores/timer';
import { hints } from './stores/hints';

export class Game {
    constructor() {
        // 初始时给一个空的 Sudoku 对象，防止测试脚本访问 this.sudoku.grid 崩溃
        this.sudoku = new Sudoku(); 
        this.history = [];
        this.isPaused = false;
    }

    startNew(diff) {
        // 只有当 store 存在时才调用（增加鲁棒性）
        if (difficulty && difficulty.set) difficulty.set(diff);
        
        this.sudoku = Sudoku.generate(diff);
        this.history = [];
        
        // 重置外部状态（增加安全检查）
        if (cursor?.reset) cursor.reset();
        if (timer?.reset) timer.reset();
        if (hints?.reset) hints.reset();
        
        this.resume();
        if (typeof location !== 'undefined') location.hash = '';
    }

    makeMove(row, col, value) {
        if (this.isPaused) return;
        
        // 存入历史记录（深拷贝）
        this.history.push(this.sudoku.clone());
        this.sudoku.guess(row, col, value);
    }

    undo() {
        if (this.history.length > 0) {
            this.sudoku = this.history.pop();
        }
    }

    pause() {
        if (timer?.stop) timer.stop();
        if (gamePaused?.set) gamePaused.set(true);
        this.isPaused = true;
    }

    resume() {
        if (timer?.start) timer.start();
        if (gamePaused?.set) gamePaused.set(false);
        this.isPaused = false;
    }
}

// 修改点：不要只导出单例，也要导出类
// 这样测试脚本可以用 createGame() 里的 new Game()，而你的 UI 可以继续用这个单例
export const gameInstance = new Game(); 
export default gameInstance;
